{"obj_description": "New objective function combines passenger and taxi waiting times, total required travel distance, and a balancing term to prevent overloading taxis.", "obj_code": "def dynamic_obj_func(self):
    print("Creating dynamic objectives for Assignment Model")
    # Passenger waiting time component
    cost1 = gb.quicksum(
        max(self.taxi[v].arrival_time - self.passenger[p].arrTime, 0) * self.y[v, p]
        for v in self.taxi.keys() 
        for p in self.passenger.keys()
    )
    # Taxi waiting time component
    cost2 = gb.quicksum(
        max(self.passenger[p].arrTime - self.taxi[v].arrival_time, 0) * self.y[v, p]
        for v in self.taxi.keys() 
        for p in self.passenger.keys()
    )
    # Total required distance component
    cost3 = gb.quicksum(
        (self.distMatrix[self.taxi[v].start_pos][self.passenger[p].origin] +
         self.distMatrix[self.passenger[p].origin][self.passenger[p].destination]) * self.y[v, p]
        for v in self.taxi.keys() 
        for p in self.passenger.keys()
    )
    # Balancing component to prevent overloading
    cost4 = gb.quicksum(
        (gb.quicksum(self.y[v, p] for p in self.passenger.keys())) ** 2
        for v in self.taxi.keys()
    )
    costs = [cost1, cost2, cost3, cost4]
    weights = [100, 100, 10, 10000]
    # Build objective expression
    objective = sum(w * c for w, c in zip(weights, costs))
    self.model.setObjective(objective, gb.GRB.MINIMIZE)"}

